import React, { useState, useCallback } from 'react';
import { Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import { yearOptions } from '../../../constants/voucher';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-so-du-hop-dong';

interface OpeningContractBalanceRow {
  contractCode?: string;
  code?: string;
  customerName?: string;
  debitBalance?: number;
  creditBalance?: number;
}

const SoDuHopDongPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [year, setYear] = useState(String(new Date().getFullYear()));
  const [items, setItems] = useState<OpeningContractBalanceRow[]>([]);
  const [loading, setLoading] = useState(false);

  const load = useCallback(() => {
    setLoading(true);
    ktService.getOpeningContractBalances(Number(year))
      .then(data => setItems(data as OpeningContractBalanceRow[]))
      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, 'Lỗi tải số dư HĐ'), type: 'error' })))
      .finally(() => setLoading(false));
  }, [year, dispatch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  return (
    <div className={erp.page} data-testid={TEST_ID}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}>
          <h1 className={erp.title}><i className="fas fa-file-contract" /> Số dư hợp đồng đầu kỳ</h1>
        </div>
      </div>
      <div className={erp.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <Select
          value={year}
          onChange={e => setYear(e.target.value)}
          options={yearOptions()}
          data-testid={`${TEST_ID}-year`}
        />
        <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={load} onRefresh={load} showSearch={false} />
      </div>
      <div className={erp.tableCard} data-testid={`${TEST_ID}-table`}>
        {loading ? <div className={erp.loading}>Đang tải...</div> : items.length === 0 ? (
          <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>Chưa có số dư hợp đồng năm {year}</div>
        ) : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead><tr><th>Hợp đồng</th><th>Đối tượng</th><th className={erp.colRight}>Dư Nợ</th><th className={erp.colRight}>Dư Có</th></tr></thead>
              <tbody>{items.map((it, idx) => (
                <tr key={idx} data-testid={`${TEST_ID}-row-${idx + 1}`}>
                  <td>{String(it.contractCode ?? it.code ?? '—')}</td>
                  <td>{String(it.customerName ?? '—')}</td>
                  <td className={erp.colRight}>{formatVnd(Number(it.debitBalance ?? 0))}</td>
                  <td className={erp.colRight}>{formatVnd(Number(it.creditBalance ?? 0))}</td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default SoDuHopDongPage;
